  <body>
    <script>
        const csrftoken = document.querySelector('[name=csrfmiddlewaretoken]').value;

        function generatePostData() {
          let data = {}
          let interactionData = {}
          if (jsPsych.data.hasOwnProperty('getData')) {
            data = jsPsych.data.getData()
          } else {
            data = jsPsych.data.get().json()
            interactionData = jsPsych.data.getInteractionData().json();
          }

          let browser = {}
          try {
            browser = {
              "userAgent": navigator.userAgent,
              "windowWidth": window.innerWidth,
              "windowHeight": window.innerHeight
            }
          } catch {
            browser = {"error": "failed to access navigator or window object"}
          }

          let postData = {
            "uniqueid": "0",
            "current_trial": 0,
            "dateTime": (new Date().getTime()),
            "trialdata": data,
            "status": "finished",
            "browser": browser,
            "interactionData": interactionData
          }
          return postData
        }

        function dataSync() {
          let postData = generatePostData()
          postData["status"] = "started"
          $.ajax({
            type: "POST",
            contentType: "application/json",
            headers: {'X-CSRFToken': csrftoken},
            url : "http://notadomain",
            data : JSON.stringify(postData),
            dataType: 'text',
            error: (error) => {
              console.log(error)
            }
          })
        }
        window.dataSync = dataSync

        /* onFinish start */
        function onFinish() {
          var finished_message = `
            <div id="finished_message" style="margin:100px">
                <h1>Experiment Complete</h1>
                <p></p>
                <div id="upload_spinner">
                <p>Attempting to upload results.</p>
                <div class="lds-dual-ring"></div>
                </div>
                <div id="upload_failure" hidden="">
                  <p>
                    Failed to automatically upload results. Please upload the csv file that was automatically downloaded here:<br>
                    <a href="https://deploy.expfactory.org/prolific/participant/result/upload">https://deploy.expfactory.org/prolific/participant/result/upload</a>
                  </p>
                  <p>
                    If you are unable to access the above page or run into any issues using it please submit the current prolific study with code "NOCODE" and contact us.
                  </p>
                </div>
                <button id="next_experiment_button" type="button" class="btn btn-success" hidden="">Next Experiment</button>
            </div>`;

          let postData = generatePostData()
          document.body.insertAdjacentHTML('beforeend', finished_message)

          /* if post_url is 'local' we should save the data as a file */
          $.ajax({
            type: "POST",
            contentType: "application/json",
            headers: {'X-CSRFToken': csrftoken},
            url : "http://notadomain",
            data : JSON.stringify(postData),
            dataType: 'text',
            retryCount: 0,
            error: function(error, textStatus) {
              if (this.retryCount < 3) {
                this.retryCount++;
                setTimeout(() => $.ajax(this), 3000);
                return
              }
              document.getElementById("upload_spinner").hidden = true
              document.getElementById("upload_failure").hidden = false
              jsPsych.data.get().localSave('csv', `${new Date().getTime()}.csv`);
              window.localStorage.setItem('errorThrown', error.statusText)
            },
            success: (data) => {
              $("#next_experiment_button").click(() => {
                console.log("Finished!");
                location.reload()
              })
              document.getElementById("upload_spinner").hidden = true
              document.getElementById("next_experiment_button").hidden = false
              let old_ds = document.getElementsByClassName("display_stage_background")
              if (old_ds.length > 0) {
                old_ds[0].hidden = true
              }
              old_ds = document.getElementsByClassName("display_stage")
              if (old_ds.length > 0) {
                old_ds[0].hidden = true
              }
            }
          });
        }
        /* onFinish end */

        /* First we try to call the old style jspsych init in case we are
           loading classic experiment-factory style experiments. If this fails
           for any reason lets try to run it as a jsPsych7 experiment.
        */
        try {
          jsPsych.init({
            display_element: getDisplayElement(),
            timeline: operation_span_rdoc_experiment,
            on_finish: onFinish,
            fullscreen: true
          });
        } catch {
          jsPsych = initJsPsych({on_finish: onFinish})
          if (window.efVars && window.efVars._survey) {
            var operation_span_rdoc_experiment = survey_convert(window.efVars._survey)
            console.log(operation_span_rdoc_experiment)
          }
          if (window.hasOwnProperty("operation_span_rdoc_init")) {
            operation_span_rdoc_init()
          }
          jsPsych.run(operation_span_rdoc_experiment)
        }
    </script>
  </body>
</html>


