                      nav_html += pagenum_display;
                  }
                  nav_html +=
                      "<button id='jspsych-instructions-next' class='jspsych-btn'" +
                          "style='margin-left: 5px;'>" +
                          trial.button_label_next +
                          " &gt;</button></div>";
