function makeAsymmetricGrids() {
  for (var i = 0; i < 100; i++) {
    var obj = makeAsymmetricArrays()[0];
    var grid = combineArrays(obj.firstGrid, obj.secondGrid);
    asymmetricGrids.push({ grid: grid, symmetric: obj.symmetric });
