const csrftoken = document.querySelector('[name=csrfmiddlewaretoken]').value;

        function generatePostData() {
          let data = {}
          let interactionData = {}
          if (jsPsych.data.hasOwnProperty('getData')) {
            data = jsPsych.data.getData()
          } else {
            data = jsPsych.data.get().json()
            interactionData = jsPsych.data.getInteractionData().json();
          }

          let browser = {}
          try {
            browser = {
              "userAgent": navigator.userAgent,
              "windowWidth": window.innerWidth,
              "windowHeight": window.innerHeight
            }
          } catch {
            browser = {"error": "failed to access navigator or window object"}
          }

          let postData = {
            "uniqueid": "0",
            "current_trial": 0,
            "dateTime": (new Date().getTime()),
            "trialdata": data,
            "status": "finished",
            "browser": browser,
            "interactionData": interactionData
          }
          return postData
        }

        function dataSync() {
          let postData = generatePostData()
          postData["status"] = "started"
          $.ajax({
            type: "POST",
            contentType: "application/json",
            headers: {'X-CSRFToken': csrftoken},
            url : "http://notadomain",
            data : JSON.stringify(postData),
            dataType: 'text',
            error: (error) => {
              console.log(error)
            }
          })
        }
        window.dataSync = dataSync

        /* onFinish start */
